package com.hospital.management.dao.impl;import com.hospital.management.dao.RoomDao;import com.hospital.management.model.*;import com.hospital.management.util.DatabaseConnectionManager;import java.sql.*;import java.util.*;public class RoomDaoImpl implements RoomDao{private static final String S="SELECT r.*,d.DEPARTMENT_NAME,(SELECT COUNT(*) FROM BEDS b WHERE b.ROOM_ID=r.ROOM_ID) TOTAL_BEDS,(SELECT COUNT(*) FROM BEDS b WHERE b.ROOM_ID=r.ROOM_ID AND b.STATUS='AVAILABLE') AVAILABLE_BEDS FROM ROOMS r LEFT JOIN DEPARTMENTS d ON d.DEPARTMENT_ID=r.DEPARTMENT_ID ";public Optional<Room>findById(Long id)throws SQLException{return one("r.ROOM_ID",id);}public Optional<Room>findByRoomNumber(String n)throws SQLException{return one("r.ROOM_NUMBER",n);}private Optional<Room>one(String f,Object v)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(S+"WHERE "+f+"=?")){s.setObject(1,v);try(ResultSet r=s.executeQuery()){return r.next()?Optional.of(map(r)):Optional.empty();}}}public Page<Room>findAll(PageRequest p,Long dep,String type,String st)throws SQLException{String w="WHERE (? IS NULL OR UPPER(r.ROOM_NUMBER||' '||r.ROOM_TYPE||' '||r.FLOOR_NUMBER||' '||NVL(d.DEPARTMENT_NAME,'')||' '||r.STATUS) LIKE ?) AND (? IS NULL OR r.DEPARTMENT_ID=?) AND (? IS NULL OR r.ROOM_TYPE=?) AND (? IS NULL OR r.STATUS=?) ";String x=p.getSearchTerm().isBlank()?null:"%"+p.getSearchTerm().toUpperCase()+"%",t=blank(type),z=blank(st);try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(S+w+"ORDER BY r.FLOOR_NUMBER,r.ROOM_NUMBER OFFSET ? ROWS FETCH NEXT ? ROWS ONLY")){int i=1;s.setString(i++,x);s.setString(i++,x);pair(s,i,dep);i+=2;s.setString(i++,t);s.setString(i++,t);s.setString(i++,z);s.setString(i++,z);s.setInt(i++,p.getOffset());s.setInt(i,p.getPageSize());List<Room>a=new ArrayList<>();try(ResultSet r=s.executeQuery()){while(r.next())a.add(map(r));}return new Page<>(a,p.getPageNumber(),p.getPageSize(),a.size()<p.getPageSize()?p.getOffset()+a.size():p.getOffset()+a.size()+1);}}public List<Room>findActiveRooms()throws SQLException{return findAll(new PageRequest(1,100,""),null,null,"ACTIVE").getContent();}public long create(Room r)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("INSERT INTO ROOMS(ROOM_NUMBER,ROOM_TYPE,FLOOR_NUMBER,DEPARTMENT_ID,DAILY_RATE,STATUS)VALUES(?,?,?,?,?,?)",new String[]{"ROOM_ID"})){bind(s,r);s.executeUpdate();try(ResultSet x=s.getGeneratedKeys()){return x.next()?x.getLong(1):0;}}}public boolean update(Room r)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("UPDATE ROOMS SET ROOM_NUMBER=?,ROOM_TYPE=?,FLOOR_NUMBER=?,DEPARTMENT_ID=?,DAILY_RATE=?,STATUS=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE ROOM_ID=?")){bind(s,r);s.setLong(7,r.getRoomId());return s.executeUpdate()==1;}}private void bind(PreparedStatement s,Room r)throws SQLException{s.setString(1,r.getRoomNumber());s.setString(2,r.getRoomType());s.setInt(3,r.getFloorNumber());if(r.getDepartmentId()==null)s.setNull(4,Types.NUMERIC);else s.setLong(4,r.getDepartmentId());s.setBigDecimal(5,r.getDailyRate());s.setString(6,r.getStatus());}public boolean updateStatus(Long id,String st)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("UPDATE ROOMS SET STATUS=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE ROOM_ID=?")){s.setString(1,st);s.setLong(2,id);return s.executeUpdate()==1;}}public boolean existsByRoomNumber(String n)throws SQLException{return findByRoomNumber(n).isPresent();}public boolean existsByRoomNumberExcludingId(String n,Long id)throws SQLException{return findByRoomNumber(n).filter(r->!r.getRoomId().equals(id)).isPresent();}public boolean hasOccupiedBeds(Long id)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("SELECT 1 FROM BEDS WHERE ROOM_ID=? AND STATUS='OCCUPIED' FETCH FIRST 1 ROW ONLY")){s.setLong(1,id);try(ResultSet r=s.executeQuery()){return r.next();}}}private void pair(PreparedStatement s,int i,Long v)throws SQLException{if(v==null){s.setNull(i,Types.NUMERIC);s.setNull(i+1,Types.NUMERIC);}else{s.setLong(i,v);s.setLong(i+1,v);}}private String blank(String s){return s==null||s.isBlank()?null:s.toUpperCase();}private Room map(ResultSet r)throws SQLException{Room x=new Room();x.setRoomId(r.getLong("ROOM_ID"));x.setRoomNumber(r.getString("ROOM_NUMBER"));x.setRoomType(r.getString("ROOM_TYPE"));x.setFloorNumber(r.getInt("FLOOR_NUMBER"));long d=r.getLong("DEPARTMENT_ID");x.setDepartmentId(r.wasNull()?null:d);x.setDepartmentName(r.getString("DEPARTMENT_NAME"));x.setDailyRate(r.getBigDecimal("DAILY_RATE"));x.setStatus(r.getString("STATUS"));x.setTotalBeds(r.getInt("TOTAL_BEDS"));x.setAvailableBeds(r.getInt("AVAILABLE_BEDS"));return x;}}
